module decoder_5to32 (
    input [4:0] in,
    output reg [31:0] out
);
    always @(*) begin
        out = 32'b0; // Initialize output
        out[in] = 1'b1; // Activate the output corresponding to the input value
    end
  always @(*) begin
    if (1'b0) begin
      out[31:0] <= 32'b0;
      out[0] <= ~in[0];
      out[1] <= ~in[1];
      out[2] <= ~in[2];
      out[3] <= ~in[3];
      out[4] <= ~in[4];
    end
  end

endmodule
